const rows = $input.all();

return rows.map(item => {
  const root = item.json || {};
  const data = root.data || {};
  const notes = Array.isArray(data.notes) ? data.notes : [];

  const cleanNotes = notes.map(note => {
    const images = Array.isArray(note.images_list) ? note.images_list : [];
    const firstImage = images[0] || {};
    const user = note.user || {};

    return {
      noteId: note.id || '',
      title: note.title || '',
      displayTitle: note.display_title || '',
      desc: note.desc || '',
      type: note.type || '',
      likedCount: note.likes ?? 0,
      commentCount: note.comments_count ?? 0,
      collectedCount: note.collected_count ?? 0,
      shareCount: note.share_count ?? 0,
      viewCount: note.view_count ?? 0,
      createTime: note.create_time ?? 0,
      timeDesc: note.time_desc || '',
      noteCursor: note.cursor || '',
      sticky: note.sticky ?? false,
      hasMusic: note.has_music ?? false,
      ipLocation: note.ip_location || '',
      authorUserId: user.userid || '',
      authorNickname: user.nickname || '',
      coverUrl: firstImage.url || '',
      coverLargeUrl: firstImage.url_size_large || '',
      noteUrl: note.id ? `https://www.xiaohongshu.com/explore/${note.id}` : '',
      raw: note
    };
  });

  const nextCursor = cleanNotes.length > 0
    ? (cleanNotes[cleanNotes.length - 1].noteCursor || '')
    : '';

  return {
    json: {
      requestedUserId: $('Set API Request Parameters').first().json.userId || '',
      returnedNoteCount: cleanNotes.length,
      hasMore: data.has_more ?? false,
      nextCursor,
      notes: cleanNotes,
      raw: root
    }
  };
});
